"""
offlinai_shell — tiny POSIX-like shell emulator that runs inside the
OfflinAi Python runtime. iOS has no /bin/bash, no fork(), no
subprocess — so we implement every builtin the user actually needs in
pure Python and fall back to evaluating the line as Python for anything
else.

Call `run_line(cmd)` once per user input. The function itself does:

  1. If the line is empty / a comment → print nothing, return.
  2. Tokenise with `shlex.split`.
  3. If the first token is a registered builtin → call its handler.
  4. Otherwise interpret the line as Python code (multi-line statements
     are accumulated until `code.compile_command()` says they're done).

The emulator prints to stdout/stderr directly — the Swift terminal
captures them through PythonRuntime's existing streaming hooks.

Keep this file PURE PYTHON and stdlib-only. It must load on a vanilla
CPython with no extensions.
"""

from __future__ import annotations

import builtins
import code
import contextlib
import fnmatch
import io
import os
import runpy
import shlex
import shutil
import stat as _stat
import sys
import time
import traceback
from pathlib import Path
from typing import Callable, Dict, List, Optional

# ---------------------------------------------------------------------------
# ANSI helpers — the Swift terminal supports SGR color codes.

def _c(n: int) -> str:   return f"\x1b[{n}m"
RESET = _c(0)
BOLD  = _c(1)
DIM   = _c(2)
RED   = _c(31)
GRN   = _c(32)
YLW   = _c(33)
BLU   = _c(34)
MAG   = _c(35)
CYN   = _c(36)
WHT   = _c(37)
GRAY  = _c(90)


def _color(path: Path) -> str:
    """Pick an ls color based on the file type/extension."""
    try:
        st = path.lstat()
    except OSError:
        return GRAY
    if _stat.S_ISDIR(st.st_mode):   return BLU + BOLD
    if _stat.S_ISLNK(st.st_mode):   return CYN
    if path.suffix in {".py", ".pyi"}:        return YLW
    if path.suffix in {".md", ".txt", ".rst"}: return WHT
    if path.suffix in {".png", ".jpg", ".jpeg", ".gif", ".svg", ".mp4"}: return MAG
    if path.suffix in {".json", ".yaml", ".yml", ".toml"}:              return CYN
    if st.st_mode & 0o111:  # executable
        return GRN + BOLD
    return ""


def _fmt_size(n: int) -> str:
    for unit in ("B", "K", "M", "G", "T"):
        if n < 1024:
            return f"{n:>5.0f}{unit}" if unit == "B" else f"{n:>5.1f}{unit}"
        n /= 1024
    return f"{n:.1f}P"


# ---------------------------------------------------------------------------
# Shell state

class Shell:
    # Real interactive namespace for Python lines.
    def __init__(self) -> None:
        import __main__
        self.globals: dict = __main__.__dict__
        self.pending: List[str] = []      # buffer for multi-line Python
        self.aliases: Dict[str, str] = {
            "ll": "ls -lah",
            "la": "ls -a",
            "cls": "clear",
            "py": "python",
            "h":  "help",
            "?":  "help",
        }
        self.home = str(Path.home())
        self.start_time = time.time()
        # Users can't chdir into the read-only app bundle, so default to
        # the writable Documents folder on first launch.
        try:
            docs_workspace = Path("~/Documents/Workspace").expanduser()
            if docs_workspace.is_dir():
                os.chdir(docs_workspace)
        except OSError:
            pass

    # ── Prompt ───────────────────────────────────────────────────────
    def prompt(self) -> str:
        """The PS1 string — shown before each new command."""
        cwd = os.getcwd()
        if cwd.startswith(self.home):
            cwd = "~" + cwd[len(self.home):]
        return f"{GRN}{BOLD}offlinai{RESET} {BLU}{cwd}{RESET} {DIM}${RESET} "

    def ps2(self) -> str:
        return f"{DIM}...{RESET}   "

    # ── Entry point ───────────────────────────────────────────────────
    def run_line(self, line: str) -> None:
        """Execute one user input line and stream results to stdout."""
        # If we're in multi-line Python input mode, keep accumulating.
        if self.pending:
            self.pending.append(line)
            src = "\n".join(self.pending)
            try:
                compiled = code.compile_command(src, "<shell>", "single")
            except SyntaxError as e:
                self.pending.clear()
                print(f"{RED}SyntaxError:{RESET} {e}")
                return
            if compiled is None:
                return  # still incomplete — caller shows PS2
            self.pending.clear()
            self._exec_compiled(compiled)
            return

        if not line.strip() or line.strip().startswith("#"):
            return

        # Alias expansion (single level, first word only)
        first, _, rest = line.lstrip().partition(" ")
        if first in self.aliases:
            line = self.aliases[first] + (" " + rest if rest else "")

        # Explicit Python escape: line starts with "%" or ">>" or ":"
        if line.lstrip().startswith(("%", ">>>", ":py ")):
            py = line.lstrip().lstrip("%").lstrip(":py ").lstrip(">>> ").lstrip()
            self._run_python(py)
            return

        # Tokenise; bail early on quote mismatch so assignments still work.
        try:
            tokens = shlex.split(line, comments=False, posix=True)
        except ValueError:
            tokens = []

        if tokens and tokens[0] in BUILTINS:
            try:
                BUILTINS[tokens[0]](self, tokens[1:])
            except SystemExit:
                raise  # let a sys.exit from a script propagate
            except KeyboardInterrupt:
                print(f"\n{YLW}^C{RESET}")
            except Exception as e:
                print(f"{RED}{type(e).__name__}:{RESET} {e}")
                if os.environ.get("OFFLINAI_SHELL_DEBUG"):
                    traceback.print_exc()
            return

        # Fallback: try the whole line as Python.
        self._run_python(line)

    # ── Python evaluation ─────────────────────────────────────────────
    def _run_python(self, src: str) -> None:
        try:
            compiled = code.compile_command(src, "<shell>", "single")
        except SyntaxError as e:
            print(f"{RED}SyntaxError:{RESET} {e}")
            return
        if compiled is None:
            # Need more lines.
            self.pending.append(src)
            return
        self._exec_compiled(compiled)

    def _exec_compiled(self, compiled) -> None:
        try:
            exec(compiled, self.globals)
        except SystemExit:
            raise
        except KeyboardInterrupt:
            print(f"\n{YLW}^C{RESET}")
        except BaseException:
            traceback.print_exc()


# ---------------------------------------------------------------------------
# Builtin commands

BUILTINS: Dict[str, Callable[["Shell", List[str]], None]] = {}


def builtin(name: str):
    def deco(fn):
        BUILTINS[name] = fn
        return fn
    return deco


@builtin("help")
def _help(sh: Shell, argv: List[str]) -> None:
    cmds = sorted(BUILTINS)
    width = max(len(c) for c in cmds) + 2
    print(f"{BOLD}OfflinAi shell{RESET} — built-in commands:\n")
    for i, c in enumerate(cmds):
        end = "\n" if (i + 1) % 5 == 0 else ""
        print(f"  {GRN}{c:<{width}}{RESET}", end=end)
    if (len(cmds)) % 5 != 0:
        print()
    print("""
Anything not listed above is evaluated as Python. Examples:

  {c}ls{r}                 list files in the current directory
  {c}cd ..{r}              change directory
  {c}cat foo.py{r}         dump a file to the terminal
  {c}python foo.py arg{r}  run a .py file in the current interpreter
  {c}pip install rich{r}   install a pure-Python package
  {c}2 + 2{r}              evaluate Python
  {c}import numpy as np{r} import and keep the binding

Aliases: ll, la, cls (→ clear), py (→ python), h/? (→ help)
""".format(c=CYN, r=RESET))


@builtin("pwd")
def _pwd(sh: Shell, argv: List[str]) -> None:
    print(os.getcwd())


@builtin("cd")
def _cd(sh: Shell, argv: List[str]) -> None:
    if not argv or argv[0] == "~":
        target = sh.home
    elif argv[0] == "-":
        target = os.environ.get("OLDPWD", sh.home)
    else:
        target = os.path.expanduser(os.path.expandvars(argv[0]))
        # iOS: /tmp resolves to /private/var/tmp (system, read-only for
        # sandboxed apps). Redirect to the writable per-app tmp.
        import tempfile
        if target in ("/tmp", "/private/var/tmp"):
            target = tempfile.gettempdir()
            print(f"{DIM}(cd: /tmp → {target} — iOS sandbox){RESET}")
    prev = os.getcwd()
    try:
        os.chdir(target)
        os.environ["OLDPWD"] = prev
        os.environ["PWD"] = os.getcwd()
    except OSError as e:
        print(f"{RED}cd:{RESET} {e.strerror}: {target}")


def _list_entries(path: Path, show_hidden: bool) -> List[Path]:
    try:
        entries = list(path.iterdir())
    except (OSError, PermissionError) as e:
        print(f"{RED}ls:{RESET} {e.strerror}: {path}")
        return []
    if not show_hidden:
        entries = [e for e in entries if not e.name.startswith(".")]
    entries.sort(key=lambda p: (not p.is_dir(), p.name.lower()))
    return entries


@builtin("ls")
def _ls(sh: Shell, argv: List[str]) -> None:
    long = "l" in "".join(a for a in argv if a.startswith("-") and not a.startswith("--"))
    show_hidden = "a" in "".join(a for a in argv if a.startswith("-"))
    human = "h" in "".join(a for a in argv if a.startswith("-"))
    paths = [a for a in argv if not a.startswith("-")] or ["."]
    for idx, p in enumerate(paths):
        base = Path(os.path.expanduser(p))
        if not base.exists():
            print(f"{RED}ls:{RESET} no such path: {p}")
            continue
        if base.is_file():
            _print_one(base, long=long, human=human)
            continue
        if len(paths) > 1:
            if idx: print()
            print(f"{BOLD}{base}:{RESET}")
        for entry in _list_entries(base, show_hidden):
            _print_one(entry, long=long, human=human)


def _print_one(p: Path, *, long: bool, human: bool) -> None:
    color = _color(p)
    name = p.name + ("/" if p.is_dir() else "")
    if not long:
        print(f"{color}{name}{RESET}")
        return
    try:
        st = p.lstat()
    except OSError:
        print(f"{color}{name}{RESET}"); return
    perms = _stat.filemode(st.st_mode)
    size = _fmt_size(st.st_size) if human else f"{st.st_size:>8d}"
    mtime = time.strftime("%b %d %H:%M", time.localtime(st.st_mtime))
    print(f"{GRAY}{perms}{RESET}  {size}  {GRAY}{mtime}{RESET}  {color}{name}{RESET}")


@builtin("cat")
def _cat(sh: Shell, argv: List[str]) -> None:
    if not argv:
        print(f"{RED}cat:{RESET} usage: cat <file> [<file> …]")
        return
    for arg in argv:
        path = Path(os.path.expanduser(arg))
        try:
            data = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as e:
            print(f"{RED}cat:{RESET} {e}")
            continue
        # No syntax highlighting here — Pygments is optional.
        sys.stdout.write(data)
        if not data.endswith("\n"):
            sys.stdout.write("\n")


@builtin("head")
def _head(sh: Shell, argv: List[str]) -> None:
    n = 10
    args: List[str] = []
    it = iter(argv)
    for a in it:
        if a == "-n":
            try: n = int(next(it))
            except (StopIteration, ValueError):
                print(f"{RED}head:{RESET} -n needs an integer"); return
        elif a.startswith("-") and a[1:].isdigit():
            n = int(a[1:])
        else:
            args.append(a)
    if not args:
        print(f"{RED}head:{RESET} usage: head [-n N] <file>"); return
    for p in args:
        try:
            with open(os.path.expanduser(p)) as f:
                for i, line in enumerate(f):
                    if i >= n: break
                    sys.stdout.write(line)
        except OSError as e:
            print(f"{RED}head:{RESET} {e}")


@builtin("tail")
def _tail(sh: Shell, argv: List[str]) -> None:
    n = 10
    args: List[str] = []
    it = iter(argv)
    for a in it:
        if a == "-n":
            try: n = int(next(it))
            except (StopIteration, ValueError):
                print(f"{RED}tail:{RESET} -n needs an integer"); return
        elif a.startswith("-") and a[1:].isdigit():
            n = int(a[1:])
        else:
            args.append(a)
    if not args:
        print(f"{RED}tail:{RESET} usage: tail [-n N] <file>"); return
    for p in args:
        try:
            with open(os.path.expanduser(p)) as f:
                lines = f.readlines()[-n:]
                sys.stdout.write("".join(lines))
        except OSError as e:
            print(f"{RED}tail:{RESET} {e}")


@builtin("mkdir")
def _mkdir(sh: Shell, argv: List[str]) -> None:
    recursive = "-p" in argv
    args = [a for a in argv if not a.startswith("-")]
    for a in args:
        path = Path(os.path.expanduser(a))
        try:
            path.mkdir(parents=recursive, exist_ok=recursive)
        except OSError as e:
            print(f"{RED}mkdir:{RESET} {e}")


@builtin("rm")
def _rm(sh: Shell, argv: List[str]) -> None:
    recursive = any(a in ("-r", "-rf", "-R", "-fr") for a in argv)
    force = any("f" in a for a in argv if a.startswith("-"))
    args = [a for a in argv if not a.startswith("-")]
    if not args:
        print(f"{RED}rm:{RESET} usage: rm [-rf] <path> …"); return
    for a in args:
        path = Path(os.path.expanduser(a))
        try:
            if path.is_dir() and not path.is_symlink():
                if not recursive:
                    print(f"{RED}rm:{RESET} {a} is a directory (use -r)"); continue
                shutil.rmtree(path)
            else:
                path.unlink()
        except FileNotFoundError:
            if not force:
                print(f"{RED}rm:{RESET} no such file: {a}")
        except OSError as e:
            print(f"{RED}rm:{RESET} {e}")


@builtin("rmdir")
def _rmdir(sh: Shell, argv: List[str]) -> None:
    for a in argv:
        try:
            os.rmdir(os.path.expanduser(a))
        except OSError as e:
            print(f"{RED}rmdir:{RESET} {e}")


@builtin("touch")
def _touch(sh: Shell, argv: List[str]) -> None:
    for a in argv:
        path = Path(os.path.expanduser(a))
        try:
            path.touch(exist_ok=True)
        except OSError as e:
            print(f"{RED}touch:{RESET} {e}")


@builtin("cp")
def _cp(sh: Shell, argv: List[str]) -> None:
    recursive = any(a in ("-r", "-R") for a in argv)
    args = [a for a in argv if not a.startswith("-")]
    if len(args) < 2:
        print(f"{RED}cp:{RESET} usage: cp [-r] <src> <dst>"); return
    *srcs, dst = (os.path.expanduser(a) for a in args)
    for src in srcs:
        try:
            if os.path.isdir(src):
                if not recursive:
                    print(f"{RED}cp:{RESET} {src} is a directory (use -r)"); continue
                shutil.copytree(src, dst)
            else:
                shutil.copy2(src, dst)
        except OSError as e:
            print(f"{RED}cp:{RESET} {e}")


@builtin("mv")
def _mv(sh: Shell, argv: List[str]) -> None:
    if len(argv) < 2:
        print(f"{RED}mv:{RESET} usage: mv <src> <dst>"); return
    *srcs, dst = (os.path.expanduser(a) for a in argv)
    for src in srcs:
        try:
            shutil.move(src, dst)
        except OSError as e:
            print(f"{RED}mv:{RESET} {e}")


@builtin("echo")
def _echo(sh: Shell, argv: List[str]) -> None:
    print(" ".join(argv))


@builtin("env")
def _env(sh: Shell, argv: List[str]) -> None:
    for k in sorted(os.environ):
        print(f"{CYN}{k}{RESET}={os.environ[k]}")


@builtin("export")
def _export(sh: Shell, argv: List[str]) -> None:
    for a in argv:
        if "=" not in a:
            print(f"{RED}export:{RESET} expected NAME=VALUE, got {a!r}"); continue
        k, _, v = a.partition("=")
        os.environ[k] = v


@builtin("which")
def _which(sh: Shell, argv: List[str]) -> None:
    for name in argv:
        if name in BUILTINS:
            print(f"{name}: shell builtin")
        elif name in sh.aliases:
            print(f"{name}: aliased to {sh.aliases[name]!r}")
        elif (mod := sys.modules.get(name)) is not None:
            src = getattr(mod, "__file__", "built-in")
            print(f"{name}: Python module at {src}")
        else:
            print(f"{RED}which:{RESET} {name} not found")


@builtin("date")
def _date(sh: Shell, argv: List[str]) -> None:
    print(time.strftime("%a %b %d %H:%M:%S %Z %Y"))


@builtin("uptime")
def _uptime(sh: Shell, argv: List[str]) -> None:
    d = int(time.time() - sh.start_time)
    h, d = divmod(d, 3600)
    m, s = divmod(d, 60)
    print(f"shell up {h}h {m}m {s}s")


@builtin("clear")
def _clear(sh: Shell, argv: List[str]) -> None:
    # Swift terminal watches for this exact escape and wipes the text view.
    sys.stdout.write("\x1b[2J\x1b[H")
    sys.stdout.flush()


@builtin("grep")
def _grep(sh: Shell, argv: List[str]) -> None:
    if len(argv) < 2:
        print(f"{RED}grep:{RESET} usage: grep [-i] <pattern> <file> …"); return
    import re
    flags = 0
    pat_args = list(argv)
    if pat_args and pat_args[0].startswith("-"):
        opt = pat_args.pop(0)
        if "i" in opt: flags |= re.IGNORECASE
    if len(pat_args) < 2:
        print(f"{RED}grep:{RESET} missing files"); return
    pattern = re.compile(pat_args[0], flags)
    for path in pat_args[1:]:
        try:
            with open(os.path.expanduser(path)) as f:
                for i, line in enumerate(f, 1):
                    if pattern.search(line):
                        sys.stdout.write(f"{BLU}{path}{RESET}:{GRN}{i}{RESET}: {line}")
        except OSError as e:
            print(f"{RED}grep:{RESET} {e}")


@builtin("find")
def _find(sh: Shell, argv: List[str]) -> None:
    if not argv:
        root, pattern = ".", "*"
    elif len(argv) == 1:
        root, pattern = argv[0], "*"
    else:
        root = argv[0]
        if argv[1] == "-name" and len(argv) >= 3:
            pattern = argv[2]
        else:
            pattern = argv[1]
    try:
        for base, dirs, files in os.walk(os.path.expanduser(root)):
            for name in dirs + files:
                if fnmatch.fnmatch(name, pattern):
                    print(os.path.join(base, name))
    except OSError as e:
        print(f"{RED}find:{RESET} {e}")


@builtin("tree")
def _tree(sh: Shell, argv: List[str]) -> None:
    root = Path(os.path.expanduser(argv[0])) if argv else Path(".")

    def _walk(p: Path, prefix: str) -> None:
        try:
            entries = sorted(p.iterdir(), key=lambda x: (not x.is_dir(), x.name.lower()))
        except OSError:
            return
        entries = [e for e in entries if not e.name.startswith(".")]
        for i, entry in enumerate(entries):
            last = i == len(entries) - 1
            connector = "└── " if last else "├── "
            print(f"{prefix}{GRAY}{connector}{RESET}{_color(entry)}{entry.name}{RESET}")
            if entry.is_dir() and not entry.is_symlink():
                ext = "    " if last else "│   "
                _walk(entry, prefix + ext)

    print(f"{_color(root)}{root}{RESET}")
    _walk(root, "")


@builtin("wc")
def _wc(sh: Shell, argv: List[str]) -> None:
    for p in argv or ["-"]:
        try:
            text = (sys.stdin.read() if p == "-" else Path(os.path.expanduser(p)).read_text())
        except (OSError, UnicodeDecodeError) as e:
            print(f"{RED}wc:{RESET} {e}"); continue
        lines = text.count("\n")
        words = len(text.split())
        chars = len(text)
        print(f"  {lines:7d}  {words:7d}  {chars:7d}  {p}")


@builtin("history")
def _history(sh: Shell, argv: List[str]) -> None:
    # The Swift side keeps history — this is a placeholder that tells
    # the user how to use it.
    print("History: press ↑ or ↓ in the terminal input field.")


@builtin("exit")
@builtin("quit")
def _exit(sh: Shell, argv: List[str]) -> None:
    print(f"{DIM}(exit ignored — the Python interpreter keeps running){RESET}")


# ---------------------------------------------------------------------------
# Running Python scripts: `python foo.py`

@builtin("python")
@builtin("python3")
def _python(sh: Shell, argv: List[str]) -> None:
    """Run a .py file or a -c snippet in the existing interpreter."""
    if not argv or argv[0] in ("-h", "--help"):
        print("usage: python <file.py> [arg …]   |   python -c \"<code>\"")
        return

    if argv[0] == "-c":
        if len(argv) < 2:
            print(f"{RED}python -c:{RESET} expected argument"); return
        code_str = argv[1]
        sh._run_python(code_str)
        return

    if argv[0] == "-m":
        if len(argv) < 2:
            print(f"{RED}python -m:{RESET} expected module name"); return
        mod = argv[1]
        old_argv = sys.argv[:]
        sys.argv = [mod, *argv[2:]]
        try:
            runpy.run_module(mod, run_name="__main__", alter_sys=True)
        except SystemExit:
            pass
        except BaseException:
            traceback.print_exc()
        finally:
            sys.argv = old_argv
        return

    # Script path
    script = os.path.expanduser(argv[0])
    if not os.path.isfile(script):
        print(f"{RED}python:{RESET} no such file: {script}"); return
    old_argv = sys.argv[:]
    sys.argv = [script, *argv[1:]]
    try:
        runpy.run_path(script, run_name="__main__")
    except SystemExit as e:
        # Show exit code only if non-zero — keep output clean on success
        code_ = e.code if isinstance(e.code, int) else (1 if e.code else 0)
        if code_:
            print(f"{DIM}[exit {code_}]{RESET}")
    except BaseException:
        traceback.print_exc()
    finally:
        sys.argv = old_argv


# ---------------------------------------------------------------------------
# pip runner — reuses the same in-process pip that the Packages tab uses.

@builtin("pip")
@builtin("pip3")
def _pip(sh: Shell, argv: List[str]) -> None:
    os.environ.setdefault("PIP_DISABLE_PIP_VERSION_CHECK", "1")
    os.environ.setdefault("PIP_NO_CACHE_DIR", "1")

    user_site = os.path.expanduser("~/Documents/site-packages")
    os.makedirs(user_site, exist_ok=True)
    if user_site not in sys.path:
        sys.path.insert(0, user_site)

    try:
        from pip._internal.cli.main import main as pip_main
    except Exception as e:
        print(f"{RED}pip:{RESET} not available: {e}")
        return

    # For `pip install X` force --target so we don't try to touch the
    # read-only app bundle.
    args = list(argv)
    if args and args[0] == "install":
        if "--target" not in args and "-t" not in args:
            args = [args[0], "--target", user_site, "--upgrade", "--no-warn-script-location", *args[1:]]
    try:
        rc = pip_main(args)
    except SystemExit as e:
        rc = int(e.code) if e.code is not None else 0
    if rc:
        print(f"{YLW}pip exited with code {rc}{RESET}")
    # Refresh import caches so freshly-installed packages become
    # visible without restarting the interpreter.
    try:
        import importlib
        importlib.invalidate_caches()
    except Exception:
        pass


# ---------------------------------------------------------------------------
# Module-level singleton

shell = Shell()


def run_line(line: str) -> None:
    """Public entry point used by Swift: `offlinai_shell.run_line(line)`."""
    shell.run_line(line)


def prompt() -> str:
    return shell.prompt()


def ps2() -> str:
    return shell.ps2()


def pending_continuation() -> bool:
    """Whether the shell is still collecting a multi-line Python block."""
    return bool(shell.pending)
